import { useState } from "react";

const winningLines = [
  [[0, 0], [0, 1], [0, 2]],
  [[1, 0], [1, 1], [1, 2]],
  [[2, 0], [2, 1], [2, 2]],

  [[0, 0], [1, 0], [2, 0]],
  [[0, 1], [1, 1], [2, 1]],
  [[0, 2], [1, 2], [2, 2]],

  [[0, 0], [1, 1], [2, 2]],
  [[0, 2], [1, 1], [2, 0]],
];

function findWinner(board) {
  for (const [a, b, c] of winningLines) {
    if (
      board[a[0]][a[1]] &&
      board[a[0]][a[1]] === board[b[0]][b[1]] &&
      board[b[0]][b[1]] === board[c[0]][c[1]]
    ) {
      return board[a[0]][a[1]];
    }
  }
}

function emptyBoard() {
  return [
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ];
}

export default function TicTacToe() {
  const [board, setBoard] = useState(emptyBoard());
  const [player, setPlayer] = useState("❌");

  const winner = findWinner(board);

  function play(r, c) {
    if (board[r][c] || winner) return;

    const next = board.map(row => [...row]);
    next[r][c] = player;

    setBoard(next);
    setPlayer(player === "❌" ? "⭕" : "❌");
  }

  return (
    <main>
      <h1>⭕ Tic Tac Toe ❌</h1>

      <p>{winner ? `${winner} Wins! 🎉` : `Turn: ${player}`}</p>

      <article>
        {board.map((row, r) => (
          <p
            key={r}
            style={{
              display: "flex",
              justifyContent: "center",
              gap: "0.5rem",
            }}
          >
            {row.map((cell, c) => (
              <button
                key={c}
                onClick={() => play(r, c)}
                style={{
                  width: "4rem",
                  height: "4rem",
                  fontSize: "2rem",
                }}
              >
                {cell}
              </button>
            ))}
          </p>
        ))}
      </article>

      <button onClick={() => {
        setBoard(emptyBoard());
        setPlayer("❌");
      }}>
        Play Again
      </button>
    </main>
  );
}
